#include <stdio.h>
#include <stdlib.h> // Required for malloc and free

int main() {
    int N;
    // Read the number of elements
    if (scanf("%d", &N) != 1) {
        fprintf(stderr, "Failed to read N.\n");
        return 1;
    }

    if (N <= 0 || N > 100) {
        fprintf(stderr, "N must be between 1 and 100.\n");
        return 1;
    }

    // Dynamically allocate memory for N integers
    int *arr = (int *)malloc(N * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1; // Indicate an error
    }

    // Read N integers into the dynamically allocated array using pointer arithmetic
    for (int i = 0; i < N; ++i) {
        if (scanf("%d", arr + i) != 1) { // arr + i is equivalent to &arr[i]
            fprintf(stderr, "Failed to read element %d.\n", i);
            free(arr); // Free memory before exiting on error
            return 1;
        }
    }

    // Calculate the sum using pointer arithmetic
    long long sum = 0; // Use long long for sum to prevent overflow with many ints
    for (int i = 0; i < N; ++i) {
        sum += *(arr + i); // *(arr + i) is equivalent to arr[i]
    }

    // Print the sum
    printf("%lld\n", sum);

    // Free the dynamically allocated memory
    free(arr);
    arr = NULL; // Good practice to set pointer to NULL after freeing

    return 0; // Indicate successful execution
}

#include <stdio.h>
#include <stdlib.h> // For malloc, free
#include <string.h> // For strlen, strcpy, strcspn

int main() {
    char buffer[101]; // Temporary buffer for reading input (max 99 chars + null + newline)
    if (fgets(buffer, sizeof(buffer), stdin) == NULL) {
        fprintf(stderr, "Failed to read string.\n");
        return 1;
    }

    // Remove trailing newline if present
    buffer[strcspn(buffer, "\n")] = 0;

    int len = strlen(buffer);
    if (len == 0) { // Handle empty string case
        printf("\n");
        return 0;
    }

    // Dynamically allocate memory for the string
    char *str = (char *)malloc((len + 1) * sizeof(char)); // +1 for null terminator
    if (str == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }
    strcpy(str, buffer); // Copy content to dynamic memory

    // Reverse the string in place using pointers
    char *start = str;
    char *end = str + len - 1;

    while (start < end) {
        char temp = *start;
        *start = *end;
        *end = temp;
        start++;
        end--;
    }

    // Print the reversed string
    printf("%s\n", str);

    // Free the dynamically allocated memory
    free(str);
    str = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // For malloc, free

int main() {
    int N;
    if (scanf("%d", &N) != 1) {
        fprintf(stderr, "Failed to read N.\n");
        return 1;
    }

    if (N <= 0 || N > 100) {
        fprintf(stderr, "N must be between 1 and 100.\n");
        return 1;
    }

    int *arr = (int *)malloc(N * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    for (int i = 0; i < N; ++i) {
        if (scanf("%d", arr + i) != 1) {
            fprintf(stderr, "Failed to read element %d.\n", i);
            free(arr);
            return 1;
        }
    }

    // Find the maximum element and its index using pointer arithmetic
    int max_val = *arr; // Initialize with the first element
    int max_idx = 0;

    for (int i = 1; i < N; ++i) { // Start from the second element
        if (*(arr + i) > max_val) { // Compare current element with max_val
            max_val = *(arr + i);
            max_idx = i;
        }
    }

    printf("%d %d\n", max_val, max_idx);

    free(arr);
    arr = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // For malloc, free
#include <string.h> // For strlen, strcpy, strcat, strcspn

int main() {
    char buffer1[51]; // Max 49 chars + null + newline
    char buffer2[51]; // Max 49 chars + null + newline

    // Read the first string
    if (fgets(buffer1, sizeof(buffer1), stdin) == NULL) {
        fprintf(stderr, "Failed to read first string.\n");
        return 1;
    }
    buffer1[strcspn(buffer1, "\n")] = 0; // Remove newline

    // Read the second string
    if (fgets(buffer2, sizeof(buffer2), stdin) == NULL) {
        fprintf(stderr, "Failed to read second string.\n");
        // No dynamic memory allocated yet, so no need to free.
        return 1;
    }
    buffer2[strcspn(buffer2, "\n")] = 0; // Remove newline

    int len1 = strlen(buffer1);
    int len2 = strlen(buffer2);

    // Allocate memory for the concatenated string (len1 + len2 + 1 for null terminator)
    char *str_combined = (char *)malloc((len1 + len2 + 1) * sizeof(char));
    if (str_combined == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    // Copy first string
    strcpy(str_combined, buffer1);
    // Concatenate second string
    strcat(str_combined, buffer2);

    printf("%s\n", str_combined);

    free(str_combined);
    str_combined = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // For malloc, realloc, free

int main() {
    int N;
    if (scanf("%d", &N) != 1 || N < 1 || N > 10) {
        fprintf(stderr, "Invalid N (initial size). N must be between 1 and 10.\n");
        return 1;
    }

    int *arr = (int *)malloc(N * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Initial memory allocation failed.\n");
        return 1;
    }

    for (int i = 0; i < N; ++i) {
        if (scanf("%d", arr + i) != 1) {
            fprintf(stderr, "Failed to read initial element %d.\n", i);
            free(arr);
            return 1;
        }
    }

    int M;
    if (scanf("%d", &M) != 1 || M < 1 || M > 20) {
        fprintf(stderr, "Invalid M (final size). M must be between 1 and 20.\n");
        free(arr); // Free initial allocation before exiting
        return 1;
    }

    if (M > N) { // Need to expand
        int *temp_arr = (int *)realloc(arr, M * sizeof(int));
        if (temp_arr == NULL) {
            fprintf(stderr, "Memory reallocation failed. Keeping original array size N.\n");
            // If realloc fails, original 'arr' is still valid. Continue with N elements.
            M = N; // Adjust M to N, so we print existing N elements
        } else {
            arr = temp_arr;
            // Read new elements into the expanded part
            for (int i = N; i < M; ++i) {
                if (scanf("%d", arr + i) != 1) {
                    fprintf(stderr, "Failed to read new element %d after realloc.\n", i);
                    // If reading fails mid-way, print what we have successfully read
                    M = i; // Adjust M to reflect actually read elements
                    break;
                }
            }
        }
    } else {
        // M <= N, no new elements needed, conceptually truncate
        // The array 'arr' is already valid for at least M elements.
        // A realloc to a smaller size is also possible but not strictly needed for this problem
        // since we just need to print the first M elements.
    }

    // Print the elements up to M (or N if realloc failed or M > N was truncated to N)
    for (int i = 0; i < M; ++i) {
        printf("%d%s", *(arr + i), (i == M - 1) ? "" : " ");
    }
    printf("\n");

    free(arr);
    arr = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // For malloc, free
#include <string.h> // For strlen, strcpy, strcspn
#include <ctype.h>  // For tolower

int main() {
    char buffer[101]; // Temporary buffer for reading input
    if (fgets(buffer, sizeof(buffer), stdin) == NULL) {
        fprintf(stderr, "Failed to read string.\n");
        return 1;
    }
    buffer[strcspn(buffer, "\n")] = 0; // Remove trailing newline

    int len = strlen(buffer);
    if (len == 0) { // Handle empty string case
        printf("0\n");
        return 0;
    }

    // Dynamically allocate memory for the string
    char *str = (char *)malloc((len + 1) * sizeof(char));
    if (str == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }
    strcpy(str, buffer);

    int vowel_count = 0;
    char *ptr = str; // Pointer to iterate through the string

    while (*ptr != '\0') {
        char lower_char = tolower((unsigned char)*ptr); // Convert to lowercase for case-insensitive check
        if (lower_char == 'a' || lower_char == 'e' || lower_char == 'i' ||
            lower_char == 'o' || lower_char == 'u') {
            vowel_count++;
        }
        ptr++; // Move to the next character
    }

    printf("%d\n", vowel_count);

    free(str);
    str = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // For malloc, free

int main() {
    int N;
    if (scanf("%d", &N) != 1) {
        fprintf(stderr, "Failed to read N.\n");
        return 1;
    }

    if (N <= 0 || N > 100) {
        fprintf(stderr, "N must be between 1 and 100.\n");
        return 1;
    }

    int *input_arr = (int *)malloc(N * sizeof(int));
    if (input_arr == NULL) {
        fprintf(stderr, "Memory allocation for input array failed.\n");
        return 1;
    }

    for (int i = 0; i < N; ++i) {
        if (scanf("%d", input_arr + i) != 1) {
            fprintf(stderr, "Failed to read element %d.\n", i);
            free(input_arr);
            return 1;
        }
    }

    // First pass to count odd numbers
    int odd_count = 0;
    for (int i = 0; i < N; ++i) {
        if (*(input_arr + i) % 2 != 0) { // Check if odd
            odd_count++;
        }
    }

    // Dynamically allocate memory for the new array of odd numbers
    int *odd_arr = NULL;
    if (odd_count > 0) { // Only allocate if there are odd numbers
        odd_arr = (int *)malloc(odd_count * sizeof(int));
        if (odd_arr == NULL) {
            fprintf(stderr, "Memory allocation for odd numbers array failed.\n");
            free(input_arr);
            return 1;
        }

        // Second pass to populate the new array
        int current_odd_idx = 0;
        for (int i = 0; i < N; ++i) {
            if (*(input_arr + i) % 2 != 0) {
                *(odd_arr + current_odd_idx) = *(input_arr + i);
                current_odd_idx++;
            }
        }
    }

    // Print the odd numbers
    for (int i = 0; i < odd_count; ++i) {
        printf("%d%s", *(odd_arr + i), (i == odd_count - 1) ? "" : " ");
    }
    printf("\n"); // Always print a newline, even if no odd numbers

    free(input_arr);
    free(odd_arr); // Free the second array too
    input_arr = NULL;
    odd_arr = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // For malloc, free

// Function to swap two elements in an array using pointers
void swap_elements(int* arr, int index1, int index2) {
    if (arr == NULL) {
        return; // Handle null array case
    }
    // Access elements using pointer arithmetic and dereference
    int temp = *(arr + index1);
    *(arr + index1) = *(arr + index2);
    *(arr + index2) = temp;
}

int main() {
    int N;
    if (scanf("%d", &N) != 1) {
        fprintf(stderr, "Failed to read N.\n");
        return 1;
    }

    if (N <= 0 || N > 100) {
        fprintf(stderr, "N must be between 1 and 100.\n");
        return 1;
    }

    int *arr = (int *)malloc(N * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    for (int i = 0; i < N; ++i) {
        if (scanf("%d", arr + i) != 1) {
            fprintf(stderr, "Failed to read element %d.\n", i);
            free(arr);
            return 1;
        }
    }

    int idx1, idx2;
    if (scanf("%d %d", &idx1, &idx2) != 2) {
        fprintf(stderr, "Failed to read indices.\n");
        free(arr);
        return 1;
    }

    // Validate indices
    if (idx1 < 0 || idx1 >= N || idx2 < 0 || idx2 >= N) {
        fprintf(stderr, "Invalid indices provided.\n");
        free(arr);
        return 1;
    }

    // Call the swap function
    swap_elements(arr, idx1, idx2);

    // Print the modified array
    for (int i = 0; i < N; ++i) {
        printf("%d%s", *(arr + i), (i == N - 1) ? "" : " ");
    }
    printf("\n");

    free(arr);
    arr = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // For malloc, free

int main() {
    int R, C;
    if (scanf("%d %d", &R, &C) != 2) {
        fprintf(stderr, "Failed to read R and C.\n");
        return 1;
    }

    if (R < 1 || R > 10 || C < 1 || C > 10) {
        fprintf(stderr, "R and C must be between 1 and 10.\n");
        return 1;
    }

    // Dynamically allocate a 2D array (array of pointers to int arrays)
    int **matrix = (int **)malloc(R * sizeof(int *));
    if (matrix == NULL) {
        fprintf(stderr, "Memory allocation for matrix rows failed.\n");
        return 1;
    }

    for (int i = 0; i < R; ++i) {
        matrix[i] = (int *)malloc(C * sizeof(int));
        if (matrix[i] == NULL) {
            fprintf(stderr, "Memory allocation for matrix column %d failed.\n", i);
            // Free previously allocated rows
            for (int j = 0; j < i; ++j) {
                free(matrix[j]);
            }
            free(matrix);
            return 1;
        }
    }

    // Read elements into the matrix
    for (int i = 0; i < R; ++i) {
        for (int j = 0; j < C; ++j) {
            if (scanf("%d", &matrix[i][j]) != 1) {
                fprintf(stderr, "Failed to read element at (%d, %d).\n", i, j);
                // Free all allocated memory before exiting
                for (int k = 0; k < R; ++k) {
                    free(matrix[k]);
                }
                free(matrix);
                return 1;
            }
        }
    }

    if (R != C) {
        printf("Not a square matrix\n");
    } else {
        long long main_diag_sum = 0;
        long long anti_diag_sum = 0;

        for (int i = 0; i < R; ++i) {
            main_diag_sum += matrix[i][i];         // Main diagonal: row == col
            anti_diag_sum += matrix[i][R - 1 - i]; // Anti-diagonal: row + col = R - 1
        }
        printf("%lld %lld\n", main_diag_sum, anti_diag_sum);
    }

    // Free dynamically allocated memory
    for (int i = 0; i < R; ++i) {
        free(matrix[i]);
    }
    free(matrix);
    matrix = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // For malloc, free
#include <string.h> // For strlen, strcpy, strcspn
#include <ctype.h>  // For isspace

int main() {
    char buffer[202]; // Max 200 chars + null + newline
    if (fgets(buffer, sizeof(buffer), stdin) == NULL) {
        fprintf(stderr, "Failed to read string.\n");
        return 1;
    }
    buffer[strcspn(buffer, "\n")] = 0; // Remove trailing newline

    int len = strlen(buffer);
    if (len == 0) { // Handle empty string case
        printf("0\n");
        return 0;
    }

    // Dynamically allocate memory for the string
    char *str = (char *)malloc((len + 1) * sizeof(char));
    if (str == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }
    strcpy(str, buffer);

    int word_count = 0;
    int in_word = 0; // Flag to track if currently inside a word
    char *ptr = str;

    while (*ptr != '\0') {
        if (isspace((unsigned char)*ptr)) {
            in_word = 0; // No longer in a word if a space is encountered
        } else if (in_word == 0) { // Start of a new word
            word_count++; 
            in_word = 1;
        }
        ptr++;
    }

    printf("%d\n", word_count);

    free(str);
    str = NULL;

    return 0;
}
